alter table achievements
add column if not exists full_description text;

update achievements
set full_description = case slug

    when 'agat' then $$Советский 8-битный персональный компьютер, разработанный прежде всего для использования в школах и учебных классах информатики. «Агат» стал одной из первых попыток создать в СССР машину, пригодную не только для научных и производственных задач, но и для массового обучения программированию и базовым навыкам работы с вычислительной техникой. По архитектуре он во многом был вдохновлён Apple II, а в аппаратной основе использовал процессор семейства MOS 6502. Компьютер поддерживал кассетные накопители, а позднее — и 5,25-дюймовые дискеты, что делало его заметным этапом в развитии школьной информатики в СССР.$$ 

    when 'elektronika-bk-0010' then $$Советский домашний 16-битный персональный компьютер, ставший одним из самых известных бытовых компьютеров в СССР. BK-0010 разрабатывался как доступная машина для домашних пользователей, школьников, студентов и любителей программирования и был совместим с архитектурой PDP-11. В его основе использовался процессор К1801ВМ1, а одной из характерных особенностей было подключение к обычному телевизору вместо отдельного монитора. Программы и данные обычно загружались с кассетных магнитофонов, а сам компьютер сыграл важную роль в популяризации домашней вычислительной техники в СССР.$$ 

    when 'ibm-pc-compatible-prototypes' then $$IBM PC-совместимые советские прототипы представляли собой экспериментальные персональные компьютеры, создававшиеся в СССР для достижения совместимости с архитектурой западных IBM PC. Их появление было связано с тем, что стандарт IBM PC постепенно становился международной основой персональных компьютеров, а совместимость с ним открывала доступ к более универсальным программным решениям и привычной логике работы. Советские инженеры стремились адаптировать эти стандарты к отечественной электронной базе и производственным условиям. Многие такие машины остались на уровне прототипов, опытных образцов или выставочных экспонатов, но они показали переход советской отрасли от собственных закрытых архитектур к попыткам интеграции с мировыми технологическими стандартами.$$ 

    when 'besm' then $$БЭСМ — одна из самых известных ранних советских электронных вычислительных машин, созданная для сложных научных, инженерных и оборонных расчётов. Она относилась к числу наиболее мощных компьютеров Европы начала 1950-х годов и развивала направление высокопроизводительных вычислений в СССР. Машина использовалась для космических и оборонных задач, а её быстродействие по меркам времени делало её важнейшим инструментом в вычислительных центрах страны. БЭСМ стала важным этапом становления советской школы компьютеростроения и показала, что в СССР возможно создание собственных ЭВМ высокого класса.$$ 

    when 'besm-6' then $$БЭСМ-6 — одна из самых известных и наиболее удачных советских электронных вычислительных машин, созданная для выполнения сложных научных, инженерных и оборонных расчётов. Она долгое время оставалась одной из главных вычислительных платформ в научных институтах СССР и обладала производительностью порядка миллиона операций в секунду. Машина широко использовалась в научных исследованиях, математическом моделировании, обработке сложных технических данных, а также в проектах, связанных с космической программой, аэродинамикой, баллистикой и прикладной математикой. БЭСМ-6 стала символом зрелости советской школы компьютеростроения и важным этапом развития высокопроизводительных вычислений в стране.$$ 

    when 'strela' then $$«Стрела» — одна из первых серийных советских электронных вычислительных машин, созданная на раннем этапе становления отечественной вычислительной техники. Она разрабатывалась как мощный вычислительный комплекс для решения особо важных государственных задач, прежде всего в оборонной и научной сферах, а её разработка велась в СКБ-245 в Москве. Машина использовалась для военных и баллистических расчётов, а также в работах, связанных с ядерной программой СССР. Особую историческую ценность «Стрелы» определяет то, что это была не просто экспериментальная разработка, а именно серийная ЭВМ: было изготовлено около семи экземпляров, что стало важным шагом от лабораторных образцов к промышленному выпуску вычислительной техники.$$ 

    when 'ural' then $$«Урал» — серия универсальных советских электронных вычислительных машин, в которую входили модели «Урал-1», «Урал-2», «Урал-4» и другие. Эти компьютеры стали одними из первых ЭВМ в СССР, выпускавшихся не как единичные экспериментальные образцы, а как машины для более широкого практического применения. Серия использовалась в промышленности, инженерных расчётах, экономическом планировании, статистической обработке данных и решении научно-технических задач. Особое значение «Урала» в том, что это были одни из первых массово выпускаемых ЭВМ в СССР, сыгравших важную роль в распространении вычислительной техники и формировании советской школы компьютеростроения.$$ 

    when 'automatic-digital-machine-project-1948' then $$Проект автоматической цифровой электронной машины — первый официально оформленный в СССР проект цифровой электронной вычислительной машины, ставший важной отправной точкой в истории отечественной вычислительной техники. Его значение заключалось в формализованной концепции универсальной ЭВМ с программным управлением, то есть машины, способной выполнять широкий круг вычислений в зависимости от загруженной программы, а не только одну специализированную функцию. Такой подход оказался фундаментальным для развития современных компьютеров, поскольку делал систему гибкой и пригодной для самых разных научных, технических и прикладных задач. Историческая важность проекта состоит в том, что он ознаменовал переход от отдельных инженерных идей к практическому проектированию цифровых вычислительных машин в СССР.$$ 

    when 'm-series' then $$Серия М — это серия ранних советских универсальных электронных цифровых вычислительных машин, в которую входили модели М-1, М-2 и М-3. Именно на этих машинах отрабатывались ключевые принципы построения отечественных ЭВМ: организация памяти, система команд, хранение программы в памяти, взаимодействие вычислительных узлов и практическое применение машин для научных расчётов. М-1 открыла направление малых ЭВМ, М-2 стала развитием этих идей, а М-3 оказалась особенно влиятельной, поскольку её технические решения и документация использовались как основа для дальнейших разработок. Серия М сыграла фундаментальную роль в становлении советской школы компьютеростроения и в формировании направления универсальных ЭВМ для науки, техники и управления.$$ 

    when 'setun' then $$«Сетунь» — уникальная советская вычислительная машина, ставшая одной из самых необычных разработок в истории мировой компьютерной техники. Её главная особенность состояла в использовании не двоичной, а троичной системы счисления, где применялись три состояния вместо двух; это делало машину не просто техническим экспериментом, а альтернативным направлением развития вычислительной техники. В машине использовалась симметричная троичная система, а сама аппаратная реализация стала одной из ранних советских безламповых разработок. «Сетунь» не осталась чисто лабораторным образцом: до 1965 года было выпущено 46 экземпляров, многие из которых использовались в университетах СССР.$$ 

    when 'elektronika-70' then $$«Электроника-70» — советская настольная программируемая вычислительная машина профессионального класса, предназначенная для научно-технических, инженерных и прикладных расчётов. По своему назначению она занимала промежуточное положение между обычным калькулятором и специализированной малой вычислительной системой: её можно было использовать для повторяющихся вычислений, автоматизации обработки измерений и решения типовых задач без обращения к крупным ЭВМ. Ключевой особенностью машины была программируемость: пользователь мог заранее задавать последовательность команд и многократно использовать составленную программу. Возможность подключения внешних устройств — графопостроителей, печатающих устройств, перфоленты и накопителей — делала её центром небольшой автоматизированной системы для обработки и вывода данных.$$ 

    when 'asu' then $$Автоматизированные системы управления (АСУ) — это комплексные человеко-машинные системы, в которых вычислительная техника, программное обеспечение, каналы связи, базы данных и персонал объединяются для управления производством, технологическими процессами и деятельностью предприятия. Термин «автоматизированные» здесь означает не исключение человека, а распределение функций между техникой и оператором, диспетчером, инженером или руководителем, принимающим решения на основе обработанной системой информации. В СССР АСУ особенно активно развивались с середины 1960-х годов и применялись в промышленности, энергетике, транспорте и управлении предприятиями. Их историческое значение состоит в том, что они стали важным шагом к цифровизации предприятий задолго до современных ERP-, MES- и SCADA-систем и показали, что ЭВМ могут использоваться не только для научных расчётов, но и для реального управления производством.$$ 

    when 'sm-evm' then $$Система малых ЭВМ (СМ ЭВМ) — это семейство советских малых управляющих компьютеров, созданных для автоматизации производственных, технологических и научных процессов. Разработка СМ ЭВМ активно велась в конце 1970-х и начале 1980-х годов, причём речь шла не об одной машине, а о целой системе совместимых компьютеров, периферии и программных средств. Эти комплексы использовались для сбора и обработки данных в реальном времени, контроля технологических процессов и построения информационно-управляющих систем. СМ ЭВМ стали важным этапом в развитии малых управляющих вычислительных систем в СССР и показали переход к модульным и массово применяемым решениям для автоматизации.$$ 

    when 'industrial-microprocessor-complexes' then $$Микропроцессорные управляющие комплексы промышленной автоматизации — это системы управления, построенные на базе микропроцессоров и предназначенные для контроля, регулирования и координации различных производственных процессов. Они применялись для автоматизации работы оборудования, технологических линий, станков, измерительных систем и исполнительных механизмов, а их появление стало важным этапом перехода от крупных вычислительных машин к более компактным и специализированным системам управления. Основой таких комплексов служили микропроцессоры, которые обрабатывали сигналы от датчиков, анализировали состояние оборудования и вырабатывали управляющие команды. Эти комплексы стали важным шагом к распределённой промышленной автоматике, где отдельные участки производства могли управляться автономно, оставаясь частью общей системы управления предприятием.$$ 

    when 'elbrus' then $$«Эльбрус» — это не просто отдельный процессор, а целое направление отечественной вычислительной техники, сочетающее оригинальные архитектурные решения, поддержку защищённых вычислений и ориентацию на создание независимых аппаратно-программных платформ. Архитектура семейства известна использованием длинного командного слова и возможностью динамической двоичной трансляции для совместимости с программами, созданными под другие архитектуры, в частности x86. Это позволяет запускать широкий круг программного обеспечения даже без его изначальной адаптации под «Эльбрус». Важной особенностью направления является также защищённый режим работы, что делает архитектуру особенно значимой для государственных, корпоративных и специализированных вычислительных систем.$$ 

    when 'mvs-1000m' then $$МВС-1000/М — российский суперкомпьютерный комплекс, созданный для задач, требующих высокой вычислительной производительности, масштабируемости и работы с большими объёмами данных. Он относится к классу высокопроизводительных вычислительных систем, применяемых в научных расчётах, моделировании и других задачах, где требуется параллельная обработка больших массивов информации. Архитектура подобных комплексов ориентирована на объединение множества вычислительных модулей в единую производительную среду. Исторически МВС-1000/М важен как пример развития отечественных суперкомпьютерных решений уже в постсоветский период.$$ 

    when 'yandex' then $$Яндекс — российская IT-корпорация, начавшая развитие как поисковая система и со временем превратившаяся в крупную технологическую экосистему. Сегодня её сервисы охватывают множество направлений цифровой жизни: поиск, карты, почту, покупки, транспорт, навигацию, облачные решения, инструменты для разработчиков, рекламные технологии, музыку и другие онлайн-продукты. Компания развивает продукты на основе технологий поиска, машинного обучения и обработки данных и может рассматриваться не просто как поисковик, а как многофункциональная технологическая платформа. Для истории информационных технологий Яндекс важен как пример перехода от отдельного программного сервиса к целостной цифровой экосистеме, объединяющей коммуникации, логистику, облачную инфраструктуру и интеллектуальные сервисы.$$ 

    when 'kaspersky' then $$«Лаборатория Касперского» — российская компания, работающая в области кибербезопасности и разработки программных средств защиты информации. Она известна прежде всего антивирусными решениями, но её деятельность включает значительно более широкий круг задач: защиту компьютеров, серверов, мобильных устройств и корпоративных сетей от вирусов, вредоносных программ, сетевых атак, спама и других киберугроз. Одним из ключевых направлений её деятельности является обнаружение, анализ и расследование инцидентов информационной безопасности. Исторически компания важна как пример того, как отечественная ИТ-разработка вышла на мировой рынок и заняла заметное место в сфере кибербезопасности.$$ 

    when '1c' then $$1С — российская компания, специализирующаяся на разработке, распространении и поддержке программного обеспечения для бизнеса, государственных организаций, образования и частных пользователей. Наиболее известным направлением её работы стала система «1С:Предприятие», лежащая в основе большого количества решений для бухгалтерии, кадрового учёта, торговли, документооборота, управления производством и других бизнес-процессов. Платформа представляет собой не одну программу, а целую технологическую среду, на базе которой создаются прикладные решения для разных сфер деятельности. Значение 1С состоит в том, что она объединяет технологическую платформу, прикладные решения, методическую поддержку и сеть внедрения, став фактическим стандартом автоматизации учёта и управления во множестве организаций.$$ 

    when 'postgres-pro' then $$Postgres Pro — российская система управления базами данных, созданная на основе PostgreSQL и развиваемая как более функциональная платформа для корпоративного и профессионального использования. Она ориентирована на организации, которым важны надёжность хранения данных, расширенные возможности администрирования, поддержка современных сценариев обработки информации и использование СУБД в ответственных прикладных системах. По своему положению Postgres Pro представляет уже не эпоху отдельных вычислительных машин, а этап зрелых инфраструктурных программных платформ, на которых строятся корпоративные информационные системы. Для истории отечественных информационных технологий она важна как пример развития собственной профессиональной СУБД на базе международного open-source-фундамента.$$ 

    when 'yadro' then $$YADRO — российская технологическая компания, ориентированная на создание комплексной ИТ-инфраструктуры. Она разрабатывает серверные и storage-платформы, телекоммуникационное оборудование, решения для мобильных сетей, микропроцессоры на базе открытой архитектуры RISC-V, а также программные платформы и операционные системы для собственных устройств. Это показывает, что деятельность компании охватывает не только готовые аппаратные продукты, но и более глубокий уровень технологической базы — от электроники и процессорных разработок до системного программного обеспечения. Значение YADRO состоит в том, что она формирует целостный набор технологий для дата-центров, корпоративных систем и цифровых сервисов.$$ 

    when 'kotlin' then $$Kotlin — современный кроссплатформенный статически типизированный язык программирования, разработанный для создания надёжных, удобных в сопровождении и переносимых программных систем. Изначально он получил широкое распространение в экосистеме JVM, где компилируется в байткод и может использоваться совместно с существующими Java-библиотеками и Java-инфраструктурой. Одной из важнейших его особенностей является глубокая совместимость с Java: код на Kotlin может вызывать Java-классы и методы, а Java-код — использовать Kotlin-компоненты, что делает язык удобным для внедрения даже в крупные существующие проекты. Благодаря этому Kotlin воспринимается как более современная и удобная альтернатива Java для многих практических задач.$$ 

    when 'selectel' then $$Selectel — российская технологическая компания, работающая в сфере облачной инфраструктуры, аренды серверов и услуг дата-центров. Она предоставляет вычислительные ресурсы, на базе которых можно размещать сайты, приложения, базы данных, корпоративные сервисы и другие цифровые системы, и развивает инфраструктурные сервисы класса IaaS. Компания предлагает выделенные и облачные серверы, платформы виртуализации, объектное и блочное хранилище, сетевые сервисы, резервное копирование, решения для мониторинга и инструменты для развёртывания ИТ-среды без необходимости строить собственный дата-центр. Для истории вычислительной техники Selectel важна как пример перехода от эпохи отдельных вычислительных машин к эпохе облачных платформ и сервисной инфраструктуры.$$ 

    when 'aurora-os' then $$ОС «Аврора» — специализированная российская мобильная платформа, ориентированная на организации, которым нужны централизованное администрирование, контролируемая экосистема приложений и повышенный уровень информационной безопасности. Система поддерживает безопасную аутентификацию, защищённые протоколы, работу с ключами, функции изоляции приложений и доступа к данным, а также многофакторную аутентификацию. Таким образом, «Аврора» представляет собой не просто мобильную операционную систему, а основу для построения управляемой и защищённой корпоративной мобильной среды. Её значение заключается в развитии отечественной платформы для мобильных устройств с акцентом на управляемость и безопасность.$$ 

    when 'baikal-m' then $$Baikal-M — российский энергоэффективный микропроцессор семейства Baikal, предназначенный для использования в рабочих станциях, офисных компьютерах, тонких клиентах и серверных системах. Он относится к современному этапу развития отечественной вычислительной техники, где важны не только производительность, но и создание собственной аппаратной платформы для повседневных и корпоративных задач. Процессор разрабатывался как универсальное решение для построения независимых вычислительных систем на базе отечественного или адаптированного программного обеспечения, а в его основе лежит архитектура ARMv8-A. Значение Baikal-M состоит в том, что он представляет попытку создать собственную современную процессорную платформу для широкого спектра прикладных сценариев.$$ 

    when 'kamaz-autonomous-trucks' then $$Проект «КАМАЗ (беспилотные грузовики)» — российская разработка в области интеллектуального транспорта, направленная на внедрение автономных грузоперевозок на магистральных дорогах. В рамках инициативы по созданию беспилотных логистических коридоров на трассе М-11 «Нева» было запущено движение высокоавтоматизированных грузовых автомобилей между логистическими терминалами Москвы и Санкт-Петербурга, а для беспилотного режима используются тягачи на базе модели КАМАЗ-54901. Основу таких машин составляют системы компьютерного зрения, навигации, связи и обработки входящей информации, а управление тормозами, рулевым механизмом, двигателем и коробкой передач интегрировано в электронную систему управления. По сути, это сложный киберфизический транспортный комплекс, в котором механические системы тесно связаны с программным обеспечением и цифровой обработкой данных.$$ 

    else full_description
end
